import { BaseModel, CastableTypes } from './base-model';
import { PitchType } from './pitch-type';

export class Ball extends BaseModel {
  static _cast: Partial<Record<keyof Ball, CastableTypes>> = {
    createdAt: 'date',
    updatedAt: 'date',
  };

  id!: number;
  userId: string | null = null;
  resourceId!: string;
  pitchTypeId: string | null = null;

  ballIndex!: number;
  angle: number | null = null;
  efficiency: number | null = null;
  gyroDegree: number | null = null;
  horizontalBreak: number | null = null;
  isHit!: boolean;
  isPitched!: boolean;
  exitVelocity: number | null = null;
  initialVelocity: number | null = null;
  spinDirection: number | null = null;
  totalSpin: number | null = null;
  activeSpin: number | null = null;
  verticalBreak: number | null = null;
  annotatedVideoFilename: string | null = null;
  extractedVideoFilename: string | null = null;

  presignedAnnotatedVideoUrl: string | null = null;
  presignedExtractedVideoUrl: string | null = null;

  foundAt: number | null = null;

  createdAt!: string;
  updatedAt!: string;

  pitchType: PitchType | null = null;

  constructor(data?: any) {
    super();
    this.init(Ball, data);
    this.pitchType = PitchType.newInstance(PitchType, data?.pitchType);
  }
}

