[{"name_path": "ScatterModal", "kind": "Constant", "body_location": {"start_line": 62, "end_line": 482}, "body": "ScatterModal: FC<ScatterModalParam> = ({
  isOpen,
  onClose,
  setIsOpen,
  title,
  teamId,
  sessionId,
  userId,
}) => {
  const { services } = useServicesHook();

  const unit = useSelector((state) => state.user.unit);
  const pitchTypes = useSelector((state) => state.master.pitchTypes);
  const defaultColor = 'rgba(160, 160, 160, 0.8)';
  const pitchTypeToColor = {
    // fastball
    '4_seam_fastball': 'rgba(210, 45, 73, 0.8)',
    cutter: 'rgba(147, 63, 45, 0.8)',
    sinker: 'rgba(254, 157, 0.8)',
    // vertical
    changeup: 'rgba(28, 190, 59, 0.8)',
    forkball: 'rgba(85, 204, 171, 0.8)',
    splitter: 'rgba(60, 172, 172, 0.8)',
    // dialognal
    curveball: 'rgba(1, 209, 237, 0.8)',
    knuckle_curve: 'rgba(98, 54, 205, 0.8)',
    screwball: 'rgba(96, 219, 51, 0.8)',
    slurve: 'rgba(147, 175, 212, 0.8)',
    // horizontal
    slider: 'rgba(238, 231, 23, 0.8)',
    sweeper: 'rgba(221, 179, 58, 0.8)',
    // others
    eephus: 'rgba(136, 136, 136, 0.8)',
    knuckleball: 'rgba(61, 68, 205, 0.8)',
  };
  const pitchTypeIdToPitchType = pitchTypes.reduce<Record<string, PitchType>>(
    (acc, pitchType) => {
      acc[pitchType.id] = pitchType;
      return acc;
    },
    {},
  );
  const pitchTypeIdToColor = pitchTypes.reduce<Record<string, string>>(
    (acc, pitchType) => {
      acc[pitchType.id] =
        pitchTypeToColor[
          pitchType.pitchType! as keyof typeof pitchTypeToColor
        ] ?? defaultColor;
      return acc;
    },
    {},
  );

  const [_, setIsInitialized] = useState<boolean>(false);
  const [resources, setResources] = useState<Resource[]>([]);
  const [ballsMap, setBallsMap] = useState<Record<number, Ball>>({});
  const [tooltipBallId, setTooltipBallId] = useState<number | null>(null);

  const getResources = async (teamId: string, sessionId: string) => {
    const result = await services.default.resource.getResources(
      teamId,
      sessionId,
      {
        dateFilter: 'all',
        offset: 0,
        pageSize: 1000,
        userId: userId,
      },
    );
    if (result.error) {
      // TODO
      return;
    }
    setResources(result.resources);
    setBallsMap(
      result.resources.reduce<Record<number, Ball>>((acc, resource) => {
        resource.ballInfoList.forEach((ballInfo) => {
          acc[ballInfo.ball.id] = ballInfo.ball;
        });
        return acc;
      }, {}),
    );
  };

  const initialize = async () => {
    try {
      await Promise.all([getResources(teamId, sessionId)]);
    } finally {
      setIsInitialized(true);
    }
  };

  useEffect(() => {
    // isOpenの状態変更時に「開いた」状態（isOpen === true）に変わったら初期化（セッション内resourcesデータの全取得）
    if (isOpen) {
      initialize();
    }
  }, [isOpen]);

  const R = unit === 'cm' ? 100 : 39.3701;
  const maxXY = unit === 'cm' ? 70 : 30;
  const minXY = unit === 'cm' ? -70 : -30;
  const stepXY = unit === 'cm' ? 10 : 5;

  const data = resources.flatMap((resource) =>
    resource.ballInfoList
      .filter(
        (ballInfo) =>
          ballInfo.ball.isPitched &&
          ballInfo.ball.horizontalBreak !== null &&
          ballInfo.ball.verticalBreak !== null,
      )
      .map((ballInfo) => ({
        x: ballInfo.ball.horizontalBreak! * R,
        y: ballInfo.ball.verticalBreak! * R,
        pitchTypeId: ballInfo.ball.pitchTypeId!,
        ballId: ballInfo.ball.id,
      })),
  );

  const ballIdDataMap = data.reduce<Record<number, DataPoint>>((acc, item) => {
    if (!acc[item.ballId]) {
      acc[item.ballId] = item;
    }
    return acc;
  }, {});

  const groupedData = data.reduce(
    (acc, item) => {
      if (!acc[item.pitchTypeId]) {
        acc[item.pitchTypeId] = [];
      }
      acc[item.pitchTypeId].push(item);
      return acc;
    },
    {} as Record<string, DataPoint[]>,
  );

  // 球種ごとの統計情報を計算する
  const calculateStatsByPitchType = useCallback(() => {
    const stats: Record<string, PitchTypeStats> = {};

    Object.entries(groupedData).forEach(([pitchTypeId, dataPoints]) => {
      const balls = dataPoints
        .map((dataPoint) => ballsMap[dataPoint.ballId])
        .filter(Boolean);

      if (balls.length === 0) {
        return;
      }

      // 平均値を計算する
      const velocities = balls
        .map((ball) => ball.initialVelocity)
        .filter((v) => v !== null && v !== undefined);

      const vBreaks = balls
        .map((ball) => ball.verticalBreak)
        .filter((v) => v !== null && v !== undefined);

      const hBreaks = balls
        .map((ball) => ball.horizontalBreak)
        .filter((v) => v !== null && v !== undefined);

      if (
        velocities.length === 0 ||
        vBreaks.length === 0 ||
        hBreaks.length === 0
      ) {
        return;
      }

      // 平均値を計算する
      const avgVelocity =
        velocities.reduce((sum, val) => sum + val, 0) / velocities.length;
      const avgVBreak =
        (vBreaks.reduce((sum, val) => sum + val, 0) / vBreaks.length) * R;
      const avgHBreak =
        (hBreaks.reduce((sum, val) => sum + val, 0) / hBreaks.length) * R;

      stats[pitchTypeId] = {
        avgVelocity,
        avgVBreak,
        avgHBreak,
        count: balls.length,
      };
    });

    return stats;
  }, [ballsMap, groupedData, R]);

  const pitchTypeStats = useMemo(
    () => calculateStatsByPitchType(),
    [calculateStatsByPitchType, data],
  );

  const chartData = {
    datasets: Object.entries(groupedData).map(([pitchTypeId, data]) => {
      if (pitchTypeId != undefined) {
        const pitchType = pitchTypeIdToPitchType[pitchTypeId];
        return {
          label: translate(
            `pitch_type_${pitchType.pitchType}` as TranslationKey,
          ),
          data: data,
          backgroundColor: pitchTypeIdToColor[pitchTypeId],
        };
      } else {
        return {
          label: '-',
          data: data,
          backgroundColor: defaultColor,
        };
      }
    }),
  };

  // ツールチップの表示/非表示を制御するコールバック関数
  // 対象のデータポイントに紐づくボールのIDを取得する
  const tooltipExternalCallback = useCallback(
    (context: { tooltip: TooltipModel<ChartType> }) => {
      const { tooltip } = context;

      if (tooltip.opacity === 0) {
        setTooltipBallId(null);
        return;
      }

      if (tooltip.dataPoints?.length > 0) {
        const item = tooltip.dataPoints[0];
        if (item.dataset.label && isDataPoint(item.raw)) {
          setTooltipBallId(item.raw.ballId);
        }
      }
    },
    [],
  );

  const options = {
    responsive: true,
    maintainAspectRatio: false as const, // 親要素のwidth/heightで調整するため
    plugins: {
      legend: {
        display: true,
      },
      tooltip: {
        enabled: false,
        external: tooltipExternalCallback,
      },
    },
    scales: {
      x: {
        min: minXY,
        max: maxXY,
        grid: {
          drawBorder: false,
          color: (context: any) =>
            context.tick?.value === 0
              ? 'rgba(0, 0, 0, 0.5)'
              : 'rgba(0, 0, 0, 0.1)',
          borderWidth: (context: any) => (context.tick?.value === 0 ? 2 : 1),
        },
        ticks: {
          stepSize: stepXY,
        },
        title: {
          display: true,
          text: `${translate('horizontal_break')} [${unit}]`,
        },
      },
      y: {
        min: minXY,
        max: maxXY,
        grid: {
          drawBorder: false,
          color: (context: any) =>
            context.tick?.value === 0
              ? 'rgba(0, 0, 0, 0.5)'
              : 'rgba(0, 0, 0, 0.1)',
          borderWidth: (context: any) => (context.tick?.value === 0 ? 2 : 1),
        },
        ticks: {
          stepSize: stepXY,
        },
        title: {
          display: true,
          text: `${translate('vertical_break')} [${unit}]`,
        },
      },
    },
  };

  const BallTooltip = (params: { ball: Ball; dataPoint: DataPoint }) => {
    const { ball, dataPoint } = params;

    // 並び順: V, HB, VB, SD, AS, S, E, GD
    const displayItems: Pick<BallParamFieldParam, 'type' | 'value'>[] = [
      { type: 'V', value: ball.initialVelocity },
      { type: 'HB', value: ball.horizontalBreak },
      { type: 'VB', value: ball.verticalBreak },
      { type: 'SD', value: ball.spinDirection },
      { type: 'AS', value: ball.activeSpin },
      { type: 'S', value: ball.totalSpin },
      { type: 'E', value: ball.efficiency },
      { type: 'GD', value: ball.gyroDegree },
    ];

    return (
      <Paper
        elevation={2}
        sx={{
          position: 'absolute',
          left: dataPoint.x < 0 ? '60%' : '25%', // 座標上のデータの位置を基準にしてTooltipを配置
          top: '15%',
          width: 'fit-content',
          height: 'fit-content',
          backgroundColor: (theme) =>
            alpha(theme.palette.background.paper, 0.92),
          p: 1.5,
          borderRadius: '8px',
          zIndex: (theme) => theme.zIndex.tooltip,
          pointerEvents: 'none',
          display: 'flex',
          flexDirection: 'column',
