[{"name_path": "ScatterModal", "kind": "Constant", "body_location": {"start_line": 62, "end_line": 482}, "body": "ScatterModal: FC<ScatterModalParam> = ({
  isOpen,
  onClose,
  setIsOpen,
  title,
  teamId,
  sessionId,
